$ErrorActionPreference = 'Stop'
Set-StrictMode -Version Latest

# MasterSourceCheck v1
# Generated by ContinuityMarkerSyncOneShot v1.
# Verification-only. No marker/source/stage/commit/push/runtime/tool mutation.

$RepoRoot = Join-Path $env:USERPROFILE 'OneDrive\Desktop\Nodex System\Node'
$LiveContextRoot = Join-Path $env:USERPROFILE 'OneDrive\Desktop\nodex-live-context'
$EvidenceRoot = Join-Path $env:USERPROFILE 'OneDrive\Desktop\Nodex Evidence'

$Timestamp = Get-Date -Format 'yyyyMMdd_HHmmss'
$EvidenceJsonPath = Join-Path $EvidenceRoot ("master_source_check_after_continuity_marker_sync_v1_$Timestamp.json")
$EvidenceSummaryPath = Join-Path $EvidenceRoot ("master_source_check_after_continuity_marker_sync_v1_summary_$Timestamp.txt")

function Write-TextFileUtf8NoBom {
  param([string]$Path, [string]$Text)
  $parent = Split-Path -Parent $Path
  if (-not (Test-Path -LiteralPath $parent)) {
    New-Item -ItemType Directory -Path $parent -Force | Out-Null
  }
  [System.IO.File]::WriteAllText($Path, $Text, [System.Text.UTF8Encoding]::new($false))
}

function Invoke-ProcessText {
  param([string]$FilePath, [object]$Arguments)
  $output = & $FilePath @Arguments 2>&1 | ForEach-Object { $_.ToString() }
  [pscustomobject]@{
    FilePath = $FilePath
    Arguments = $Arguments
    ExitCode = $LASTEXITCODE
    Text = ($output -join "`n")
  }
}

function Read-JsonFile {
  param([string]$Path)
  Get-Content -LiteralPath $Path -Raw | ConvertFrom-Json
}

function Get-FieldText {
  param([object]$Object, [string]$Name)
  if ($null -eq $Object) { return '' }
  if ($Object.PSObject.Properties.Name -contains $Name) {
    return [string]$Object.PSObject.Properties[$Name].Value
  }
  return ''
}

function Get-RemoteHashFromLsRemote {
  param([string]$Text)
  if ([string]::IsNullOrWhiteSpace($Text)) { return '' }
  return (($Text -split "\s+")[0])
}

$BlockedAuthorities = @(
  'nodex_source_mutation',
  'nodex_commit',
  'nodex_push',
  'live_context_source_mutation',
  'live_context_commit',
  'live_context_push',
  'runtime_execution',
  'tool_execution',
  'packet_execution_by_nodex',
  'packet_commit_by_nodex',
  'packet_push_by_nodex',
  'generated_code_approval',
  'model_output_approval',
  'prompt_output_authority',
  'self_approval_authority',
  'authority_self_expansion',
  'reward_authority',
  'autonomous_priority_authority',
  'success_signal_authority',
  'graph_expansion',
  'deep_research_authority',
  'external_review_authority',
  'advisory_output_authority',
  'direct_finding_adoption'
)
$BlockedAuthoritiesText = ($BlockedAuthorities -join "`n")

if (-not (Test-Path -LiteralPath $EvidenceRoot)) {
  New-Item -ItemType Directory -Path $EvidenceRoot -Force | Out-Null
}

$Problems = [System.Collections.Generic.List[string]]::new()
$CommandResults = @()

function Add-Problem {
  param([string]$Message)
  $Problems.Add($Message) | Out-Null
}

$latestSyncEvidence = Get-ChildItem -LiteralPath $EvidenceRoot -Filter 'continuity_marker_sync_oneshot_v1_*.json' -File |
  Sort-Object LastWriteTime -Descending |
  Select-Object -First 1

if ($null -eq $latestSyncEvidence) {
  Add-Problem 'latest ContinuityMarkerSyncOneShot v1 evidence not found'
} else {
  $syncJson = Read-JsonFile -Path $latestSyncEvidence.FullName
  if ((Get-FieldText -Object $syncJson -Name 'status') -ne 'pass') {
    Add-Problem 'latest ContinuityMarkerSyncOneShot v1 evidence is not pass'
  }
  if ((Get-FieldText -Object $syncJson -Name 'seam') -ne 'ContinuityMarkerSyncOneShot v1') {
    Add-Problem 'latest sync evidence seam mismatch'
  }
}

$nodexStatus = Invoke-ProcessText -FilePath 'git' -Arguments @('-C', $RepoRoot, 'status', '--porcelain=v1')
$CommandResults += $nodexStatus
if ($nodexStatus.ExitCode -ne 0 -or $nodexStatus.Text -ne '') {
  Add-Problem "Nodex working tree not clean: $($nodexStatus.Text)"
}

$liveStatus = Invoke-ProcessText -FilePath 'git' -Arguments @('-C', $LiveContextRoot, 'status', '--porcelain=v1')
$CommandResults += $liveStatus
if ($liveStatus.ExitCode -ne 0 -or $liveStatus.Text -ne '') {
  Add-Problem "live-context working tree not clean: $($liveStatus.Text)"
}

$liveHead = Invoke-ProcessText -FilePath 'git' -Arguments @('-C', $LiveContextRoot, 'rev-parse', 'HEAD')
$CommandResults += $liveHead
$liveOrigin = Invoke-ProcessText -FilePath 'git' -Arguments @('-C', $LiveContextRoot, 'rev-parse', 'origin/main')
$CommandResults += $liveOrigin
$liveRemote = Invoke-ProcessText -FilePath 'git' -Arguments @('-C', $LiveContextRoot, 'ls-remote', 'origin', 'refs/heads/main')
$CommandResults += $liveRemote
$remoteHash = Get-RemoteHashFromLsRemote -Text $liveRemote.Text

if ($liveHead.ExitCode -ne 0 -or $liveOrigin.ExitCode -ne 0 -or $liveRemote.ExitCode -ne 0) {
  Add-Problem 'live-context local/origin/remote verification command failed'
} elseif ($liveHead.Text -ne $liveOrigin.Text -or $liveHead.Text -ne $remoteHash) {
  Add-Problem "live-context local/origin/remote mismatch: head=[$($liveHead.Text)] origin=[$($liveOrigin.Text)] remote=[$remoteHash]"
}

$latestJsonPath = Join-Path $LiveContextRoot 'evidence_latest/latest.json'
if (-not (Test-Path -LiteralPath $latestJsonPath -PathType Leaf)) {
  Add-Problem 'latest marker JSON missing'
} else {
  $markerJson = Read-JsonFile -Path $latestJsonPath
  if ((Get-FieldText -Object $markerJson -Name 'latestCompletedSeam') -ne 'ContinuityMarkerSyncOneShot v1') {
    Add-Problem 'marker latestCompletedSeam mismatch'
  }
  if ((Get-FieldText -Object $markerJson -Name 'currentOpenSeam') -ne 'MasterSourceCheck v1') {
    Add-Problem 'marker currentOpenSeam mismatch'
  }
  if ((Get-FieldText -Object $markerJson -Name 'nextAllowedSeam') -ne 'MasterSourceCheck v1') {
    Add-Problem 'marker nextAllowedSeam mismatch'
  }
  if ((Get-FieldText -Object $markerJson -Name 'selfReferenceBoundary') -ne 'do_not_require_live_context_files_to_name_the_commit_that_contains_their_own_update') {
    Add-Problem 'marker selfReferenceBoundary mismatch'
  }
  if ((Get-FieldText -Object $markerJson -Name 'localEvidenceRemainsAuthority') -ne 'True') {
    Add-Problem 'marker localEvidenceRemainsAuthority mismatch'
  }
}

$Status = if ($Problems.Count -eq 0) { 'pass' } else { 'fail' }
$Decision = if ($Problems.Count -eq 0) { 'operator_direction_required_allowed' } else { 'master_source_check_after_marker_sync_failed' }
$NextAllowedSeam = if ($Problems.Count -eq 0) { 'OperatorDirectionRequired v1' } else { 'MasterSourceCheckAfterMarkerSyncRepair v1' }
$ProblemText = (($Problems | ForEach-Object { '- ' + $_ }) -join "`n")

$Evidence = [pscustomobject]@{
  schema = 'nodex.master_source_check.after_continuity_marker_sync.v1'
  status = $Status
  seam = 'MasterSourceCheck v1'
  verificationOnly = $true
  decision = $Decision
  createdAt = (Get-Date).ToString('o')
  repoRoot = $RepoRoot
  liveContextRoot = $LiveContextRoot
  evidenceRoot = $EvidenceRoot
  latestAuthorityEvidence = if ($null -eq $latestSyncEvidence) { '' } else { $latestSyncEvidence.FullName }
  latestCompletedSeam = 'ContinuityMarkerSyncOneShot v1'
  currentOpenSeam = 'MasterSourceCheck v1'
  markersCurrent = ($Problems.Count -eq 0)
  conflict = $false
  problemText = $ProblemText
  sourceMutationPerformed = $false
  liveContextMutationPerformed = $false
  markerRewritePerformed = $false
  stagingPerformed = $false
  commitPerformed = $false
  pushPerformed = $false
  runtimeExecutionAllowed = $false
  toolExecutionAllowed = $false
  packetExecutionByNodexAllowed = $false
  modelOutputApprovalAllowed = $false
  generatedCodeApprovalAllowed = $false
  authorityExpansionAllowed = $false
  blockedAuthoritiesText = $BlockedAuthoritiesText
  commandResults = $CommandResults
  nextAllowedSeam = $NextAllowedSeam
}

Write-TextFileUtf8NoBom -Path $EvidenceJsonPath -Text ($Evidence | ConvertTo-Json -Depth 50)

$SummaryLines = @(
  'MASTER SOURCE CHECK V1 AFTER CONTINUITY MARKER SYNC COMPLETE',
  '',
  "status: $Status",
  "decision: $Decision",
  'verification_only: true',
  '',
  'latest_completed_seam: ContinuityMarkerSyncOneShot v1',
  'current_open_seam: MasterSourceCheck v1',
  "markers_current: $($Problems.Count -eq 0)",
  'conflict: false',
  '',
  'problems:',
  $ProblemText,
  '',
  'source_mutation_performed: false',
  'live_context_mutation_performed: false',
  'marker_rewrite_performed: false',
  'staging_performed: false',
  'commit_performed: false',
  'push_performed: false',
  'runtime_execution_allowed: false',
  'tool_execution_allowed: false',
  'packet_execution_by_nodex_allowed: false',
  'model_output_approval_allowed: false',
  'generated_code_approval_allowed: false',
  'authority_expansion_allowed: false',
  '',
  'blocked_authorities:',
  $BlockedAuthoritiesText,
  '',
  "next_allowed_seam: $NextAllowedSeam",
  "evidence_json: $EvidenceJsonPath",
  "evidence_summary: $EvidenceSummaryPath"
)

$Summary = ($SummaryLines -join "`n")
Write-TextFileUtf8NoBom -Path $EvidenceSummaryPath -Text $Summary
Write-Host $Summary

if ($Status -ne 'pass') {
  exit 1
}

exit 0
